import styled, {css} from 'styled-components';

const mainColor = 'grey'
const subColor = 'black'

const selectLabel = (props) => {
    if (props.value.length) {
        return shrinkLabel
    }
    
    return ''
}


const shrinkLabel = css`
    top: -14px;
    font-size: 12px;
    color: ${mainColor};
`

export const Group = styled.div`
    position: relative;
    margin: 45px 0;

    input[type='password'] {
        letter-spacing: 0.3em;
    }
`

export const FormInputStyled = styled.input`
background: none;
background-color: white;
color: $sub-color;
font-size: 18px;
padding: 10px 10px 10px 5px;
display: block;
width: 100%;
border: none;
border-radius: 0;
border-bottom: 1px solid ${subColor};
margin: 25px 0;

&:focus {
  outline: none;
}

&:focus ~ label {
  ${selectLabel}
}
`

export const FormInputLabel = styled.label`
    color: $sub-color;
    font-size: 16px;
    font-weight: normal;
    position: absolute;
    pointer-events: none;
    left: 5px;
    top: 10px;
    transition: 300ms ease all;

    ${selectLabel}
`
